@dataclass
class TaskClassifier:
    COMPLEX_KEYWORDS = ["prove", "proof", "derive", "calculate", "solve",
                       "algorithm", "optimize", "race condition", "debug"]

    def needs_thinking(self, prompt: str) -> tuple[bool, int]:
        if any(k in prompt.lower() for k in ["prove", "proof", "integral"]):
            return True, 15000  # Hard math
        if any(k in prompt.lower() for k in ["race condition", "concurrent", "algorithm"]):
            return True, 8000   # Complex coding
        return False, 0         # Skip reasoning
